-- Seed page_content_blocks with the current hardcoded text from each marketing page.
-- This ensures the hub editor shows real current copy immediately once applied.
-- Uses WHERE NOT EXISTS idempotent insert so it's safe to re-run.

-- HOME page
INSERT INTO page_content_blocks (page_slug, block_key, label, content)
