  ('hero_line_3',               'Hero — line 3',                                             'Conditions'),
  ('hero_loc',                  'Hero — location line',                                      'Private one-to-one personal training in Worthing'),
  ('hero_subheading',           'Hero — subheading',                                         'Specialist training for people with health conditions, complex needs, and anyone the mainstream fitness industry has overlooked. Every session adapts to how you feel that day — because the same plan can be right one week and wrong the next. GP-referred clients welcome.'),
  ('hero_btn_primary',          'Hero — primary CTA button',                                 'Book a Free Consultation'),
  ('hero_btn_secondary',        'Hero — secondary CTA link',                                 'Find Out How It Works'),
  ('badge_title',               'Hero — badge title',                                        'Level 4 Qualified'),
  ('badge_sub',                 'Hero — badge subtitle',                                     'The highest PT qualification in the UK — plus cancer rehab and exercise referral'),
  ('ticker_1',                  'Ticker — item 1',                                           'Level 4 Personal Trainer'),
  ('ticker_2',                  'Ticker — item 2',                                           'Cancer Rehabilitation Specialist'),
  ('ticker_3',                  'Ticker — item 3',                                           'Exercise Referral Specialist'),
  ('ticker_4',                  'Ticker — item 4',                                           'GP-Referred Clients Welcome'),
  ('ticker_5',                  'Ticker — item 5',                                           'Private One-to-One Studio'),
  ('ticker_6',                  'Ticker — item 6',                                           'Based in Worthing'),
  ('why_tag',                   'Why — section tag',                                         'Why Eternal Fitness'),
  ('why_body',                  'Why — body paragraph',                                      'Esther Fair is a Level 4 personal trainer, Exercise Referral Specialist, and Cancer Rehabilitation Specialist based in Worthing. She specialises in rehabilitation and recovery training for cancer treatment survivors, chronic health conditions, post-surgery recovery, disabilities, and anyone with complex medical needs who has been overlooked by mainstream fitness.'),
  ('why_feat_1_title',          'Why — feature 1 title',                                     'Specialist in complex health conditions'),
  ('why_feat_1_desc',           'Why — feature 1 description',                               'Cancer rehabilitation, chronic illness, neurological conditions, post-surgical recovery, mobility limitations.'),
  ('why_feat_2_title',          'Why — feature 2 title',                                     'Strength and mobility for real life'),
  ('why_feat_2_desc',           'Why — feature 2 description',                               'Building functional strength that improves everyday movement, independence, and confidence.'),
  ('why_feat_3_title',          'Why — feature 3 title',                                     'Calm, private, one-to-one training'),
  ('why_feat_3_desc',           'Why — feature 3 description',                               'A private studio with no gym floor, no other clients, no pressure to look or perform.'),
  ('who_tag',                   'Who — section tag',                                         'Who This Is For'),
  ('who_body',                  'Who — body paragraph',                                      'I have worked with clients managing cancer, chronic illness, disability, visual impairment, neurological conditions, and complex mobility issues. I am here for the people other trainers cannot help.'),
  ('who_card_1_title',          'Who — card 1 title',                                        'People managing health conditions, disability, or injury'),
  ('who_card_1_desc',           'Who — card 1 description',                                  'Cancer rehabilitation. Chronic illness. Neurological conditions. Post-surgical recovery. Extreme mobility limitations. Level 4 qualified and exercise referral trained — I know how to work safely and effectively with complex needs.'),
  ('who_card_1_link',           'Who — card 1 link label',                                   'See Specialist Areas'),
  ('who_card_2_title',          'Who — card 2 title',                                        'People who have never felt welcome in fitness spaces'),
  ('who_card_2_desc',           'Who — card 2 description',                                  'Whether you are a complete beginner, have had negative experiences elsewhere, or simply find gyms intimidating — the private, one-to-one format at Eternal Fitness is designed to feel completely different. No dress code, no weigh-in, no comparison to anyone else.'),
  ('approach_tag',              'Approach — section tag',                                    'The Approach'),
  ('approach_body',             'Approach — body paragraph',                                 'I am always watching and always adapting. Every session starts with a check-in — energy levels, pain, sleep, what''s changed since last week. The plan for that day is set then, not before you walk through the door.'),
  ('approach_step_1_title',     'Approach — step 1 title',                                   'Every session adapts to how you feel that day'),
  ('approach_step_1_desc',      'Approach — step 1 description',                             'Fatigue, flares, bad nights, medication changes — I notice and adjust without drawing attention to it. You always leave feeling you''ve done something worthwhile.'),
  ('approach_step_2_title',     'Approach — step 2 title',                                   'Private 1-to-1 studio — no gym floor'),
  ('approach_step_2_desc',      'Approach — step 2 description',                             'No other clients. No performance pressure. No dress code. A calm, private space where the only focus is you and what you need today.'),
  ('approach_step_3_title',     'Approach — step 3 title',                                   'Functional progress — not transformation'),
  ('approach_step_3_desc',      'Approach — step 3 description',                             'Climbing stairs with less pain. Better sleep. More energy. Walking further. These are the outcomes that matter to the people I work with — and they''re the ones I build towards.'),
  ('approach_box_1_title',      'Approach — qualification box 1 title',                      'Level 4 qualified — the highest mainstream PT certification in the UK'),
  ('approach_box_1_desc',       'Approach — qualification box 1 description',                'Exercise Referral Specialist and Cancer Rehabilitation Specialist. Trained to work with GP-referred clients, chronic conditions, post-treatment recovery, and complex medical needs. Most PTs are not qualified for this work.'),
  ('approach_box_2_title',      'Approach — qualification box 2 title',                      'No weigh-ins. No judgement. No agenda.'),
  ('approach_box_2_desc',       'Approach — qualification box 2 description',                'No before-and-after framing, no expectations about what fitness should look like. The goal is what matters to you — whether that''s managing pain, regaining independence, or simply moving with more confidence.'),
  ('spec_tag',                  'Specialist — section tag',                                  'Specialist Areas'),
  ('spec_heading',              'Specialist — heading',                                      'Who I Work With'),
  ('spec_body',                 'Specialist — body paragraph',                               'Cancer rehabilitation (active treatment, in remission, post-surgery). Chronic health conditions (fibromyalgia, ME/CFS, autoimmune, diabetes, heart conditions). Disability and adaptive training. Neurological conditions. GP-referred programmes. If your situation is not listed — please still get in touch. The answer is almost always yes.'),
  ('spec_card_1_title',         'Specialist — card 1 title',                                 'Cancer Rehabilitation'),
  ('spec_card_1_desc',          'Specialist — card 1 description',                           'Specialist support during treatment, in remission, and post-surgery.'),
  ('spec_card_2_title',         'Specialist — card 2 title',                                 'Exercise for Health'),
  ('spec_card_2_desc',          'Specialist — card 2 description',                           'Blood pressure, diabetes, bone strength, mobility and more — exercise referral specialists.'),
  ('spec_card_3_title',         'Specialist — card 3 title',                                 'Visual Impairment'),
  ('spec_card_3_desc',          'Specialist — card 3 description',                           'Adapted training for people who are blind or partially sighted.'),
  ('testimonial_1',             'Testimonials — quote 1',                                    'I was so nervous about starting, but from the first session Esther put me at ease. She listened, adapted everything to my condition, and I have never felt stronger or more confident in my own body.'),
  ('testimonial_2',             'Testimonials — quote 2',                                    E'\u201CAs someone who has dealt with chronic pain for years, I was sceptical that exercise could help. The personalised approach at Eternal Fitness has genuinely changed my quality of life. I cannot recommend it enough.\u201D'),
  ('testimonial_heading',       'Testimonials — heading',                                    'Client Stories'),
  ('testimonial_body',          'Testimonials — body paragraph',                             'Progress looks different for everyone. For some it is lifting more, for others it is walking without pain, sleeping better, or simply feeling at home in their own body.'),
  ('testimonial_link',          'Testimonials — link label',                                 'Read the FAQs'),
  ('cta_tag',                   'CTA — section tag',                                         'Free Consultation'),
  ('cta_heading',               'CTA — heading',                                             'Ready to find out if this is right for you?'),
  ('cta_body',                  'CTA — body paragraph',                                      'The first conversation is free, with no commitment. I work with a small number of clients at a time — so every person gets my full attention.'),
  ('cta_btn_primary',           'CTA — primary button',                                      'Book a Free Consultation'),
  ('cta_btn_secondary',         'CTA — secondary button',                                    'Call: 07517 658 128')
) AS v(block_key, label, content)
WHERE NOT EXISTS (SELECT 1 FROM page_content_blocks WHERE page_slug = 'home' AND block_key = v.block_key);

-- ABOUT page
INSERT INTO page_content_blocks (page_slug, block_key, label, content)
SELECT 'about', v.block_key, v.label, v.content
FROM (VALUES
  ('hero_eyebrow',              'Hero — eyebrow',                                            'About Esther'),
  ('hero_heading',              'Hero — heading',                                            'About Esther Fair — Cancer Rehabilitation Specialist'),
  ('hero_subhead',              'Hero — subheading',                                         'Level 4 Personal Trainer. Cancer Rehabilitation Specialist. Exercise Referral Specialist. I know first-hand what it feels like to start from zero.'),
  ('hero_btn_primary',          'Hero — primary CTA button',                                 'Book a Free Consultation'),
  ('hero_btn_secondary',        'Hero — secondary CTA link',                                 'My Story'),
  ('badge_label',               'Hero — badge label',                                        'Level 4 Qualified'),
  ('badge_sublabel',            'Hero — badge sublabel',                                     'Cancer Rehab & Exercise Referral'),
  ('story_eyebrow',             'Story — eyebrow',                                           'My Story'),
  ('story_heading',             'Story — heading',                                           'I Have Been Where You Are'),
  ('story_p1',                  'Story — paragraph 1',                                       'I did not come to fitness from a place of confidence. There was a time when exercise felt inaccessible, intimidating, and simply not something that was meant for me. When that changed, it changed everything — my health, my recovery, my sense of what my body was capable of.'),
  ('story_p2',                  'Story — paragraph 2',                                       'That experience is the reason I became a personal trainer. Not to help people lose weight or achieve an aesthetic ideal — but to help people rehabilitate, recover, and feel stronger, more capable, and more functional in their own bodies, regardless of their health conditions or limitations.'),
  ('story_p3',                  'Story — paragraph 3',                                       'I qualified to Level 4 — the highest personal training qualification in the UK — and went further with specialist certifications in Cancer Rehabilitation and Exercise Referral. I specifically sought these qualifications to work with people who have more complex medical needs: cancer treatment survivors, those with chronic health conditions, post-surgical recovery, disabilities, and clients whose health situations have led other trainers to say they cannot help. Those are exactly the clients I am here for.'),
  ('quals_eyebrow',             'Qualifications — eyebrow',                                  'Qualifications'),
  ('quals_heading',             'Qualifications — heading',                                  'Qualified to Help Where Others Cannot'),
  ('quals_intro',               'Qualifications — intro',                                    'Most personal trainers hold a Level 3 qualification. I hold Level 4 — alongside specialist certifications that are rare in any fitness setting.'),
  ('qual_1_title',              'Qualification 1 — title',                                   'Level 4 Personal Trainer'),
  ('qual_1_desc',               'Qualification 1 — description',                             'The highest level of personal training qualification in the UK — above the Level 3 held by most personal trainers. Registered with a recognised UK fitness body.'),
  ('qual_2_title',              'Qualification 2 — title',                                   'Exercise Referral Specialist'),
  ('qual_2_desc',               'Qualification 2 — description',                             'Qualified to work with GP-referred clients and those with clinical conditions requiring adapted exercise programmes.'),
  ('qual_3_title',              'Qualification 3 — title',                                   'Cancer Rehabilitation'),
  ('qual_3_desc',               'Qualification 3 — description',                             'Specialist training to support people through cancer treatment and recovery, including those currently in active treatment.'),
  ('exp_eyebrow',               'Experience — eyebrow',                                      'Experience'),
  ('exp_heading',               'Experience — heading',                                      'Experience Across the Full Range of Human Complexity'),
  ('exp_p1',                    'Experience — paragraph 1',                                  'Over the years, I have worked with clients that most personal trainers would not know how to support — cancer treatment survivors and people in recovery, people managing serious chronic health conditions (fibromyalgia, ME/CFS, autoimmune diseases, heart conditions), people in post-surgical or post-fracture rehabilitation, people with physical disabilities and mobility limitations, clients with significant visual impairment, people with neurological conditions (Parkinson''s, MS, stroke recovery), and anyone whose health situation doesn''t fit into mainstream fitness templates.'),
  ('exp_p2',                    'Experience — paragraph 2',                                  'I mention this not to boast, but because you might be wondering whether your situation is too complicated, too medically complex, or too much. It almost certainly is not. My Cancer Rehabilitation and Exercise Referral certifications equip me to work alongside your GP, specialist, and healthcare team. Every programme is built from scratch — with complete medical awareness and respect for whatever your body, health conditions, recovery status, or history looks like.'),
  ('exp_callout_title',         'Experience — callout title',                                'Not sure if you qualify?'),
  ('phil_eyebrow',              'Philosophy — eyebrow',                                      'Philosophy'),
  ('phil_heading',              'Philosophy — heading',                                      'The Philosophy'),
  ('phil_p1',                   'Philosophy — paragraph 1',                                  'Eternal Fitness is not a weight loss service. It is not about transforming your body into something it is not. It is about rehabilitation and recovery — finding out what your body is capable of right now, with all the health conditions, medications, limitations, and recovery status it is currently dealing with — and building steadily from there.'),
  ('phil_p2',                   'Philosophy — paragraph 2',                                  'The goal is not a six-week result. It is returning to activities after cancer treatment. Being able to move with less pain. Having better fatigue management. Managing your chronic condition without fear. Recovering full function after injury. Climbing stairs. Walking further. Moving through life with more ease, capability, and confidence than before. That takes time, consistency, and working with someone who genuinely understands medical complexity and adjusts when your health or capacity changes. That is what I do.'),
  ('phil_callout_title',        'Philosophy — callout title',                                'More Than a Workout'),
  ('phil_callout_body',         'Philosophy — callout body',                                 'No weigh-ins. No before-and-after photos. No pressure to look a certain way. Just steady, meaningful progress — measured against your own baseline, not anyone else''s.'),
  ('studio_eyebrow',            'Studio — eyebrow',                                          'Studio'),
  ('studio_heading',            'Studio — heading',                                          'A Private Space in Worthing'),
  ('studio_intro',              'Studio — intro',                                            'Sessions take place in a small, private, fully equipped studio. No public gym floor. No other clients watching. No ambient pressure of what anyone else around you is doing.'),
  ('studio_card_1_title',       'Studio — card 1 title',                                     'Designed for All Abilities'),
  ('studio_card_1_desc',        'Studio — card 1 description',                               'Studio set up for disabilities, mobility limitations, and complex health needs — with equipment chosen for functional recovery, not performance aesthetics.'),
  ('studio_card_2_title',       'Studio — card 2 title',                                     'Equipment That Serves You'),
  ('studio_card_2_desc',        'Studio — card 2 description',                               'Every piece is chosen to support rehabilitation, recovery, and real-life movement. Resistance bands, mobility tools, and adaptive kit — nothing intimidating.'),
  ('studio_card_3_title',       'Studio — card 3 title',                                     'A Calm Environment'),
  ('studio_card_3_desc',        'Studio — card 3 description',                               'No gym floor, no other clients watching, no ambient pressure. Quiet, private, one-to-one sessions — because recovery needs calm, not noise.'),
  ('long_eyebrow',              'Long-Term — eyebrow',                                       'Long-Term Progress'),
  ('long_heading',              'Long-Term — heading',                                       'Why the Long-Term Approach Matters'),
  ('long_intro',                'Long-Term — intro',                                         'Quick fixes do not work. Sustainable change does — and Eternal Fitness is built around that belief.'),
  ('long_card_1_title',         'Long-Term — card 1 title',                                  'The Power of Consistency'),
  ('long_card_1_desc',          'Long-Term — card 1 description',                            'Small, steady actions repeated over time create lasting physical and mental change — without extremes.'),
  ('long_card_2_title',         'Long-Term — card 2 title',                                  'Adapting When Things Change'),
  ('long_card_2_desc',          'Long-Term — card 2 description',                            'Life and health are unpredictable. Your programme adapts with you, so progress never stops — it just looks different.'),
  ('long_card_3_title',         'Long-Term — card 3 title',                                  'Real Outcomes, Not Aesthetics'),
  ('long_card_3_desc',          'Long-Term — card 3 description',                            'Stronger, more capable, more comfortable in your body. These are the results that actually matter.'),
  ('cta_heading',               'CTA — heading',                                             'Ready to find out if this is right for you?'),
  ('cta_body',                  'CTA — body paragraph',                                      'The first conversation is free, with no commitment. I work with a small number of clients at a time — so every person gets my full attention.'),
  ('cta_btn_primary',           'CTA — primary button',                                      'Book a Free Consultation'),
  ('cta_btn_secondary',         'CTA — secondary button',                                    'Call: 07517 658 128')
) AS v(block_key, label, content)
WHERE NOT EXISTS (SELECT 1 FROM page_content_blocks WHERE page_slug = 'about' AND block_key = v.block_key);

