  ('hero_eyebrow',              'Hero — eyebrow',                                            'Personal Training'),
  ('hero_heading',              'Hero — heading',                                            'Cancer Rehabilitation and Recovery Training in Worthing'),
  ('hero_subhead',              'Hero — subheading',                                         'Private one-to-one sessions with a Cancer Rehabilitation Specialist and Exercise Referral Specialist (Level 4 qualified). Whether you are in cancer treatment, post-surgery recovery, managing a chronic condition, living with a disability, or have complex medical needs — there is a specialist programme here for you.'),
