  ('what_eyebrow',              'What to Expect — eyebrow',                                  'What to Expect'),
  ('what_heading',              'What to Expect — heading',                                  'This Is Not Like Other Personal Training'),
  ('what_p1',                   'What to Expect — paragraph 1',                              'Personal training at Eternal Fitness is not about pushing harder, going faster, or doing more. It is about rehabilitation, recovery, and what your body needs right now — whether managing a health condition, recovering from cancer treatment, or living with a disability — and building a sustainable programme around that. Sessions are private, one-to-one, and held in a small studio in Worthing where there is no gym floor, no other clients watching, and no comparison to anyone else.'),
  ('what_p2',                   'What to Expect — paragraph 2',                              'My specialist training in cancer rehabilitation and exercise referral means I am trained to adapt to medical conditions, medication side-effects, fatigue cycles, and variable capacity. I work within your GP''s or specialist''s guidance. I do not guess — I ask, I listen, and I adjust every session based on your body''s actual needs that day.'),
  ('spec_eyebrow',              'Specialist Areas — eyebrow',                                'Specialist Areas'),
  ('spec_heading',              'Specialist Areas — heading',                                'Who I Work With'),
  ('spec_intro',                'Specialist Areas — intro',                                  'I specialise in working with people who have been underserved by mainstream fitness. If your situation is not listed here, please still get in touch — the answer is almost always yes.'),
  ('spec_panel_eyebrow',        'Specialist Areas — panel eyebrow',                          'Specialist areas'),
  ('area_1_title',              'Specialist area 1 — title',                                 'Cancer & cancer rehabilitation'),
  ('area_1_desc',               'Specialist area 1 — description',                           'During active treatment, in remission, or post-surgery. I am qualified in cancer rehabilitation and adapt to wherever you are in your journey.'),
  ('area_2_title',              'Specialist area 2 — title',                                 'Chronic health conditions'),
  ('area_2_desc',               'Specialist area 2 — description',                           'Including autoimmune conditions, fibromyalgia, ME/CFS, heart conditions, diabetes, and more. Every session adapts to what your body can manage that day.'),
  ('area_3_title',              'Specialist area 3 — title',                                 'Disability & adaptive training'),
  ('area_3_desc',               'Specialist area 3 — description',                           'Physical disabilities, significant mobility limitations, and sensory impairments including visual impairment. Programmes are built around your body, not a template.'),
  ('area_4_title',              'Specialist area 4 — title',                                 'GP-referred exercise'),
  ('area_4_desc',               'Specialist area 4 — description',                           'I am qualified in exercise referral and experienced in working alongside medical guidance from GPs and healthcare teams.'),
  ('area_5_title',              'Specialist area 5 — title',                                 'Injury recovery & rehabilitation'),
  ('area_5_desc',               'Specialist area 5 — description',                           'Post-surgical, post-fracture, and musculoskeletal conditions. I work within the guidance of your physiotherapist or consultant.'),
  ('area_6_title',              'Specialist area 6 — title',                                 'Neurological conditions'),
  ('area_6_desc',               'Specialist area 6 — description',                           'Including Parkinson''s, MS, stroke recovery, and acquired brain injury. Gentle, progressive, and always adapted.'),
  ('spec_cta_learn',            'Specialist Areas — CTA learn more',                         'Learn more'),
  ('spec_cta_book',             'Specialist Areas — CTA book consultation',                  'Book a consultation'),
  ('focus_eyebrow',             'What I Work On — eyebrow',                                  'What I Work On'),
  ('focus_heading',             'What I Work On — heading',                                  'Recovery and Rehabilitation for Real Life'),
  ('focus_intro',               'What I Work On — intro',                                    'The focus is functional rehabilitation — building strength, mobility, endurance, and capability for real life during and after health conditions. Not aesthetics. Not performance metrics. Real outcomes: returning to activities after cancer treatment, climbing stairs without pain, managing fatigue, walking further, recovering independence, sleeping better, regaining confidence in your own body.'),
  ('focus_1_title',             'Focus card 1 — title',                                      'Mobility and joint health'),
  ('focus_1_desc',              'Focus card 1 — description',                                'Improving range of motion, reducing stiffness, and moving with less effort and pain day-to-day.'),
  ('focus_2_title',             'Focus card 2 — title',                                      'Functional strength'),
