  ('focus_4_title',             'Focus card 4 — title',                                      'Fatigue management'),
  ('focus_4_desc',              'Focus card 4 — description',                                'Learning how to train effectively when energy levels are variable or unpredictable — a common challenge with many health conditions.'),
