-- EXERCISE FOR HEALTH page
INSERT INTO page_content_blocks (page_slug, block_key, label, content)
SELECT 'exercise-for-health', v.block_key, v.label, v.content
FROM (VALUES
  ('hero_eyebrow',              'Hero — eyebrow',                                            'Exercise for Health'),
  ('hero_subhead',              'Hero — subheading',                                         'Exercise is one of the most evidence-based interventions for managing a wide range of health conditions. The key is having a qualified specialist who understands your condition and programmes safely around it — not a standard PT working outside their training.'),
  ('hero_btn_primary',          'Hero — primary CTA button',                                 'Book a Free Consultation'),
  ('hero_btn_secondary',        'Hero — secondary CTA link',                                 'See Conditions Covered'),
  ('badge_label',               'Hero — badge label',                                        'Exercise Referral Specialist'),
  ('approach_eyebrow',          'The Approach — eyebrow',                                    'The Approach'),
  ('approach_heading',          'The Approach — heading',                                    'Exercise for health is different from exercise for fitness'),
  ('approach_p1',               'The Approach — paragraph 1',                                'Think of it like seeing a physiotherapist rather than a personal trainer. The goal is not weight loss, not aesthetics, and not performance. The goal is health — managing your condition, building functional strength, improving quality of life.'),
  ('approach_p2',               'The Approach — paragraph 2',                                'I work the same way a physio or an osteopath does — targeting conditions, not demographics. Every session starts with a check-in. The plan for that day is set then, based on how you actually feel — not how you felt last week.'),
  ('approach_p3',               'The Approach — paragraph 3',                                'As a Level 4 Personal Trainer and Exercise Referral Specialist, I am qualified to work with clinical populations that a standard Level 3 PT is not trained for. That distinction matters.'),
  ('cond_eyebrow',              'Conditions Covered — eyebrow',                              'Conditions Covered'),
  ('cond_heading',              'Conditions Covered — heading',                              'Who I Work With'),
  ('cond_intro',                'Conditions Covered — intro',                                'If your condition is not listed here, please still get in touch. The answer is almost always yes.'),
  ('cond_panel_eyebrow',        'Conditions Covered — panel eyebrow',                        'Conditions covered'),
  ('cond_1_title',              'Condition 1 — title',                                       'High Blood Pressure'),
  ('cond_1_desc',               'Condition 1 — description',                                 'Exercise is one of the most effective ways to lower blood pressure — when it is done safely and progressively. I am qualified in exercise referral for hypertension.'),
  ('cond_2_title',              'Condition 2 — title',                                       'Type 2 Diabetes'),
  ('cond_2_desc',               'Condition 2 — description',                                 'Structured exercise improves insulin sensitivity and blood sugar management. Sessions are planned around your medication timing and monitoring needs.'),
  ('cond_3_title',              'Condition 3 — title',                                       'Bone Health & Osteoporosis'),
  ('cond_3_desc',               'Condition 3 — description',                                 'Weight-bearing and resistance exercise is clinically recommended to slow bone density loss and reduce fracture risk. Safe, load-managed progression.'),
  ('cond_4_title',              'Condition 4 — title',                                       'Visual Impairment'),
  ('cond_4_desc',               'Condition 4 — description',                                 'Adapted training for people who are blind or partially sighted. Sessions built around clear verbal instruction, consistent equipment placement, and a familiar environment.'),
  ('cond_5_title',              'Condition 5 — title',                                       'COPD & Breathing Conditions'),
  ('cond_5_desc',               'Condition 5 — description',                                 'Exercise is recommended for people with COPD to improve function and quality of life. Sessions respect breathing capacity and build gradually.'),
  ('cond_6_title',              'Condition 6 — title',                                       'Heart Conditions'),
  ('cond_6_desc',               'Condition 6 — description',                                 'Post-cardiac rehabilitation and ongoing heart condition management. I work within the guidance of your cardiologist or GP.'),
  ('cond_7_title',              'Condition 7 — title',                                       'Chronic Pain & Fibromyalgia'),
  ('cond_7_desc',               'Condition 7 — description',                                 'Gentle, progressive movement that works with pain rather than against it. Sessions adapt to your energy and pain levels on the day.'),
  ('cond_8_title',              'Condition 8 — title',                                       'Physical Disability & Adaptive Training'),
  ('cond_8_desc',               'Condition 8 — description',                                 'Exercise programmes built entirely around your body and your goals — not a template. Wheelchair users, amputees, and neurological conditions welcome.'),
  ('cond_cta_learn',            'Conditions — CTA learn more',                               'Learn more'),
  ('cond_cta_book',             'Conditions — CTA book consultation',                        'Book a consultation'),
  ('how_eyebrow',               'How It Works — eyebrow',                                    'How It Works'),
  ('how_heading',               'How It Works — heading',                                    'What to Expect from Your Sessions'),
  ('step_1_title',              'Step 1 — title',                                            'Free consultation first'),
  ('step_1_body',               'Step 1 — body',                                            'We start with a conversation — no commitment, no obligation. I want to understand your condition, your history, and your goals before we do anything else.'),
  ('step_2_title',              'Step 2 — title',                                            'Check-in at the start of every session'),
  ('step_2_body',               'Step 2 — body',                                            'How are you feeling today? Energy, pain, sleep, any changes. The session plan is finalised then — because what works one week may not be right the next.'),
  ('step_3_title',              'Step 3 — title',                                            'Progress that adapts to you'),
  ('step_3_body',               'Step 3 — body',                                            'There is no fixed template. Programmes are built around your body, your condition, and your goals — and adjusted as those things change.'),
  ('faq_eyebrow',               'FAQ — eyebrow',                                             'Common Questions'),
  ('faq_heading',               'FAQ — heading',                                             'Questions About Exercising With a Health Condition'),
  ('faq_intro',                 'FAQ — intro',                                               'If your question is not covered here, just ask — I would always rather you did.'),
  ('faq_1_title',               'FAQ 1 — question',                                          'Can I exercise if I have a health condition?'),
  ('faq_1_body',                'FAQ 1 — answer',                                            'In most cases, yes — and the evidence strongly supports it. Exercise is clinically recommended for a wide range of conditions. The key is having a qualified specialist who understands your specific condition and can programme safely around it.'),
  ('faq_2_title',               'FAQ 2 — question',                                          'Do I need a GP referral?'),
  ('faq_2_body',                'FAQ 2 — answer',                                            'No. A GP referral is welcome but not required. Many clients come independently. I will ask about your medical history and may recommend checking with your GP if there are specific contraindications to consider first.'),
  ('faq_3_title',               'FAQ 3 — question',                                          'How is this different from a regular personal trainer?'),
  ('faq_3_body',                'FAQ 3 — answer',                                            'A standard Level 3 PT is not trained to work with clinical populations. As a Level 4 Exercise Referral Specialist, I understand contraindicated exercises, medication effects, fatigue management, and how conditions affect capacity from one session to the next.'),
  ('faq_4_title',               'FAQ 4 — question',                                          'What if I am having a bad day when I come in?'),
  ('faq_4_body',                'FAQ 4 — answer',                                            'That is what the check-in is for. I adapt the session to how you actually feel — not how the plan says you should feel. You will always leave having done something genuinely useful, even on the difficult days.'),
  ('cta_heading',               'CTA — heading',                                             'Ready to find out if this is right for you?'),
  ('cta_body',                  'CTA — body paragraph',                                      'The first conversation is free, with no commitment. I work with a small number of clients at a time — so every person gets my full attention.'),
  ('cta_btn_primary',           'CTA — primary button',                                      'Book a Free Consultation'),
  ('cta_btn_secondary',         'CTA — secondary button',                                    'Call: 07517 658 128')
) AS v(block_key, label, content)
WHERE NOT EXISTS (SELECT 1 FROM page_content_blocks WHERE page_slug = 'exercise-for-health' AND block_key = v.block_key);

-- CANCER REHABILITATION page
INSERT INTO page_content_blocks (page_slug, block_key, label, content)
SELECT 'cancer-rehabilitation', v.block_key, v.label, v.content
FROM (VALUES
  ('hero_eyebrow',              'Hero — eyebrow',                                            'Cancer Rehabilitation'),
  ('hero_subhead',              'Hero — subheading',                                         'Specialist one-to-one support during treatment, in remission, and post-surgery. Exercise is now strongly evidenced as beneficial throughout the cancer journey — with the right guidance, at the right intensity, from someone qualified to provide it.'),
  ('hero_btn_primary',          'Hero — primary CTA button',                                 'Book a Free Consultation'),
  ('hero_btn_secondary',        'Hero — secondary CTA link',                                 'See Pricing'),
  ('badge_label',               'Hero — badge label',                                        'Cancer Rehab Specialist'),
  ('evidence_eyebrow',          'The Evidence — eyebrow',                                    'The Evidence'),
  ('evidence_heading',          'The Evidence — heading',                                    'Why exercise matters during the cancer journey'),
  ('evidence_p1',               'The Evidence — paragraph 1',                                'Exercise during and after cancer treatment is no longer considered risky — the evidence now strongly supports it. Research shows that appropriate exercise during chemotherapy is associated with reduced fatigue, better mood, improved immune function, and faster recovery.'),
  ('evidence_p2',               'The Evidence — paragraph 2',                                'After treatment, structured exercise has been shown to improve overall survival rates in some cancer types, reduce the risk of recurrence, and significantly improve quality of life.'),
  ('evidence_p3',               'The Evidence — paragraph 3',                                E'The qualifier is \u201Cappropriate.\u201D The intensity, type of exercise, and how it adapts to treatment side effects matters enormously \u2014 and that is where specialist training is essential.'),
  ('evidence_callout_title',    'The Evidence — callout title',                              'Cancer Rehabilitation Specialist qualification'),
  ('evidence_callout_body',     'The Evidence — callout body',                               'Trained at Level 4 to work with people during and after cancer treatment. This is a specialist qualification, not standard personal training.'),
  ('stages_eyebrow',            'Stages — eyebrow',                                          'When I Can Help'),
  ('stages_heading',            'Stages — heading',                                          'Support at Every Stage'),
  ('stage_1_title',             'Stage 1 — title',                                           'During active treatment'),
  ('stage_1_body',              'Stage 1 — body',                                            'Chemotherapy and radiotherapy significantly affect energy, immune function, and physical capacity — and those effects are unpredictable from week to week. Sessions during active treatment are lower intensity, shorter, and built around your current treatment schedule. Every session begins with a check-in.'),
  ('stage_2_title',             'Stage 2 — title',                                           'In remission'),
  ('stage_2_body',              'Stage 2 — body',                                            'Remission brings its own challenges — rebuilding fitness that has been lost, managing ongoing fatigue or side effects, and navigating the physical and emotional after-effects of treatment. Sessions progress gradually, respecting the timeline your body needs.'),
  ('stage_3_title',             'Stage 3 — title',                                           'Post-surgery'),
  ('stage_3_body',              'Stage 3 — body',                                            'Whether mastectomy, colostomy, lymph node removal, or another procedure — post-surgical return to exercise requires careful, staged progression. I work within the guidance of your surgical team and will not progress any movement without appropriate medical clearance.'),
  ('clin_eyebrow',              'Clinical Considerations — eyebrow',                         'Clinical Considerations'),
  ('clin_heading',              'Clinical Considerations — heading',                         'What I Know and How I Work'),
  ('cons_1_title',              'Consideration 1 — title',                                   'Cancer-related fatigue is different'),
  ('cons_1_body',               'Consideration 1 — body',                                    'Cancer-related fatigue (CRF) does not respond to rest the way ordinary tiredness does. It is physiologically distinct — and training must account for it. I will never push through CRF or interpret it as effort avoidance.'),
  ('cons_2_title',              'Consideration 2 — title',                                   'Lymphoedema awareness'),
  ('cons_2_body',               'Consideration 2 — body',                                    'For clients with or at risk of lymphoedema, I monitor for signs of swelling, avoid tight compression, and follow safe exercise guidelines. Exercise can actually help manage lymphoedema when programmed correctly.'),
  ('cons_3_title',              'Consideration 3 — title',                                   'Bone density'),
  ('cons_3_body',               'Consideration 3 — body',                                    'Some cancer treatments (particularly certain hormonal therapies) accelerate bone density loss. Weight-bearing and resistance exercise is clinically recommended — but load and progression must be managed carefully.'),
  ('cons_4_title',              'Consideration 4 — title',                                   'GP or oncologist sign-off'),
  ('cons_4_body',               'Consideration 4 — body',                                    'Before beginning any structured exercise programme during or shortly after treatment, I ask for GP or oncologist clearance. This is non-negotiable — not because I am being cautious, but because it is the right clinical standard.'),
  ('stat_1_label',              'Stat strip — item 1 label',                                 'Cancer rehabilitation qualified'),
  ('stat_2_label',              'Stat strip — item 2 label',                                 'Private one-to-one sessions only'),
  ('stat_3_label',              'Stat strip — item 3 label',                                 'Free, no-pressure consultation'),
  ('stat_4_label',              'Stat strip — item 4 label',                                 'Private studio, West Sussex'),
  ('faq_eyebrow',               'FAQ — eyebrow',                                             'Common Questions'),
  ('faq_heading',               'FAQ — heading',                                             'Common Questions About Cancer Rehabilitation'),
  ('faq_intro',                 'FAQ — intro',                                               'If your question is not covered here, just ask — I would always rather you did.'),
  ('faq_1_title',               'FAQ 1 — question',                                          'Is it safe to exercise during cancer treatment?'),
  ('faq_1_body',                'FAQ 1 — answer',                                            'Evidence now strongly supports exercise during cancer treatment — at the right intensity and with the right guidance. The programme must account for your specific treatment, side effects, and current capacity. I will always ask for GP or oncologist sign-off before beginning.'),
  ('faq_2_title',               'FAQ 2 — question',                                          'What is cancer-related fatigue and how do you account for it?'),
  ('faq_2_body',                'FAQ 2 — answer',                                            'Cancer-related fatigue (CRF) is physiologically different from ordinary tiredness — it does not improve with rest in the same way. I am trained to recognise CRF and programme around it. Sessions may be shorter or lower in intensity on harder days. That is not failure — it is appropriate clinical management.'),
  ('faq_3_title',               'FAQ 3 — question',                                          'When can I start exercising after surgery?'),
  ('faq_3_body',                'FAQ 3 — answer',                                            'This depends entirely on the type of surgery and your recovery. I work with the guidance of your surgical team and will not progress any movement without appropriate medical clearance.'),
  ('faq_4_title',               'FAQ 4 — question',                                          'Do you work with people during active treatment?'),
  ('faq_4_body',                'FAQ 4 — answer',                                            'Yes. I work with people during active chemotherapy or radiotherapy, people in remission, and those who have finished treatment but are rebuilding. Each stage requires a different approach — the programme is built around where you are right now.'),
  ('cta_heading',               'CTA — heading',                                             'Ready to find out if this is right for you?'),
  ('cta_body',                  'CTA — body paragraph',                                      'The first conversation is free, with no commitment. I work with a small number of clients at a time — so every person gets my full attention.'),
  ('cta_btn_primary',           'CTA — primary button',                                      'Book a Free Consultation'),
  ('cta_btn_secondary',         'CTA — secondary button',                                    'Call: 07517 658 128')
) AS v(block_key, label, content)
WHERE NOT EXISTS (SELECT 1 FROM page_content_blocks WHERE page_slug = 'cancer-rehabilitation' AND block_key = v.block_key);

