-- FAQS page
INSERT INTO page_content_blocks (page_slug, block_key, label, content)
SELECT 'faqs', v.block_key, v.label, v.content
FROM (VALUES
  ('hero_eyebrow',              'Hero — eyebrow',                                            'FAQs'),
  ('hero_heading',              'Hero — heading',                                            'Frequently Asked Questions'),
  ('hero_subhead',              'Hero — subheading',                                         'If something is stopping you from getting in touch, the answer is probably here. And if it is not — just ask.'),
  ('hero_btn_primary',          'Hero — primary CTA button',                                 'Book a Free Consultation'),
  ('hero_btn_secondary',        'Hero — secondary CTA link',                                 'Read the FAQs'),
  ('badge_label',               'Hero — badge label',                                        'No question too small'),
  ('badge_sublabel',            'Hero — badge sublabel',                                     'Just ask — I would rather you did'),
  ('sidebar_eyebrow',           'Sidebar — eyebrow',                                         'Your Questions Answered'),
  ('sidebar_heading',           'Sidebar — heading',                                         'No question is too complicated'),
  ('sidebar_body',              'Sidebar — body',                                            'I work with people whose situations are rarely straightforward. If you are wondering whether your health, disability, or circumstances make you a difficult client — they almost certainly do not.'),
  ('sidebar_jump_label',        'Sidebar — jump label',                                      'Jump to'),
  ('sidebar_btn',               'Sidebar — CTA button',                                      'Book a Free Consultation'),
  ('group_1_name',              'Group 1 — name',                                            'Getting Started'),
  ('faq_1_1_q',                 'FAQ 1.1 — question',                                        'Do I need to be fit or healthy to start?'),
  ('faq_1_1_a',                 'FAQ 1.1 — answer',                                          'No. In fact, most of my clients start from a point where conventional fitness feels inaccessible. You do not need to have exercised before, you do not need to be at a particular weight, and you do not need to be healthy in the conventional sense. The only starting point is where you are right now.'),
  ('faq_1_2_q',                 'FAQ 1.2 — question',                                        'I have never used a personal trainer before. What can I expect?'),
  ('faq_1_2_a',                 'FAQ 1.2 — answer',                                          'Everything begins with a free consultation — a relaxed conversation about what you want to achieve and what your body is currently dealing with. There is no pressure and no commitment required. From there, I will design a programme specifically for you and walk you through every exercise at a pace that feels comfortable.'),
  ('faq_1_3_q',                 'FAQ 1.3 — question',                                        'How often should I train?'),
  ('faq_1_3_a',                 'FAQ 1.3 — answer',                                          'For most clients, two sessions per week is a good starting point. For those managing health conditions or recovering from illness, one session per week may be more appropriate initially. I will recommend a frequency that is sustainable and effective for your specific situation — never more than your body can handle.'),
  ('faq_1_4_q',                 'FAQ 1.4 — question',                                        'Where are sessions held?'),
  ('faq_1_4_a',                 'FAQ 1.4 — answer',                                          'Sessions take place in a private studio in Worthing, West Sussex. The studio is used exclusively for one-to-one training — there is no public gym floor, no other clients present, and no waiting around. The address is confirmed at the point of booking.'),
  ('group_2_name',              'Group 2 — name',                                            'Health Conditions & Complex Needs'),
  ('faq_2_1_q',                 'FAQ 2.1 — question',                                        'I have cancer or am going through cancer treatment. Can you still work with me?'),
  ('faq_2_1_a',                 'FAQ 2.1 — answer',                                          'Yes. I hold a specialist qualification in cancer rehabilitation and have experience working with clients at all stages — during active treatment, in remission, and in long-term recovery. Exercise has a significant evidence base for supporting people through cancer and its treatment. I work closely with your medical team where appropriate and adapt every session to what your body can manage that day.'),
  ('faq_2_2_q',                 'FAQ 2.2 — question',                                        'I have a chronic health condition. Can personal training still help me?'),
  ('faq_2_2_a',                 'FAQ 2.2 — answer',                                          'Almost certainly yes. I am qualified in exercise referral, which means I am specifically trained to work with people who have clinical health conditions — including heart conditions, diabetes, autoimmune conditions, fibromyalgia, ME/CFS, and many others. Every programme is adapted to what your body can manage, and adjusted regularly as your health changes.'),
  ('faq_2_3_q',                 'FAQ 2.3 — question',                                        'I have a disability. Can I still do personal training?'),
  ('faq_2_3_a',                 'FAQ 2.3 — answer',                                          'Yes. I have experience working with clients with a wide range of physical disabilities and mobility limitations. Programmes are fully adaptive. If you use a wheelchair or have very limited mobility, that is the starting point — not a barrier. Please get in touch to discuss your specific situation.'),
  ('faq_2_4_q',                 'FAQ 2.4 — question',                                        'I have extremely limited mobility. Is there still something I can do?'),
  ('faq_2_4_a',                 'FAQ 2.4 — answer',                                          'Yes. My approach is to start from where you are, whatever that looks like. Some clients begin with very gentle seated exercises, breathing work, or small range-of-motion movements. Progress looks different for everyone and is always measured against your own baseline — not anyone else''s.'),
  ('faq_2_5_q',                 'FAQ 2.5 — question',                                        'I am visually impaired or blind. Can you work with me?'),
  ('faq_2_5_a',                 'FAQ 2.5 — answer',                                          'Yes. I have experience working with visually impaired clients. All exercises are adapted and described verbally in full detail, with complete awareness of sensory needs throughout every session. Please get in touch to discuss your specific situation.'),
  ('faq_2_6_q',                 'FAQ 2.6 — question',                                        'My GP has referred me for exercise. Can you help?'),
  ('faq_2_6_a',                 'FAQ 2.6 — answer',                                          'Yes. I am qualified in exercise referral and experienced in working alongside medical guidance. If you have been referred through a GP exercise scheme or have a recommendation from your doctor, I can work directly with that guidance and liaise with your healthcare team where useful.'),
  ('faq_2_7_q',                 'FAQ 2.7 — question',                                        'I have an injury. Is it safe to exercise?'),
  ('faq_2_7_a',                 'FAQ 2.7 — answer',                                          'In most cases yes, though it depends on the injury and the stage of recovery. I always start with an assessment and will not take on a client if I believe exercise would be harmful. For recent injuries or post-surgical clients, I work within the guidance of physiotherapists and medical teams.'),
  ('group_3_name',              'Group 3 — name',                                            'Inclusive Training'),
  ('faq_3_1_q',                 'FAQ 3.1 — question',                                        'Do you work with trans and non-binary clients?'),
  ('faq_3_1_a',                 'FAQ 3.1 — answer',                                          'Yes, without reservation. I work with clients across the full spectrum of gender identity and expression. You will be addressed and supported in whatever way feels right for you. If you have specific physical goals related to your gender identity, I will work with you on those without judgement.'),
  ('faq_3_2_q',                 'FAQ 3.2 — question',                                        'I have always felt uncomfortable or unwelcome in fitness spaces. Is this different?'),
  ('faq_3_2_a',                 'FAQ 3.2 — answer',                                          'This is the most common thing I hear. The private studio, the one-to-one format, and the complete absence of any mirror-and-performance culture is specifically designed to make it different. There is no dress code, no weigh-in, and no expectation of what fitness should look like. Many of my clients come to me having had negative experiences elsewhere. Most of them stay for years.'),
  ('group_4_name',              'Group 4 — name',                                            'Practicalities'),
  ('faq_4_1_q',                 'FAQ 4.1 — question',                                        'Do you offer short-term programmes?'),
